import{_ as l}from"./chunks/ue-blueprint-sidebar.DWFzsi19.js";import{_ as e}from"./chunks/floatingball.D-BT0bmL.js";import{_ as t,o as i,c as r,ag as s}from"./chunks/framework.BqfgOMAh.js";const x=JSON.parse('{"title":"产品概述","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/overview.md","filePath":"zh/guide/overview.md"}'),n={name:"zh/guide/overview.md"};function o(d,a,p,u,h,g){return i(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="产品概述" tabindex="-1">产品概述 <a class="header-anchor" href="#产品概述" aria-label="Permalink to &quot;产品概述&quot;">​</a></h1><h2 id="nexusflow-是什么" tabindex="-1">NexusFlow 是什么 <a class="header-anchor" href="#nexusflow-是什么" aria-label="Permalink to &quot;NexusFlow 是什么&quot;">​</a></h2><p>NexusFlow 是一款 <strong>AI 驱动的虚幻引擎蓝图助手</strong>。它通过自然语言对话的方式，帮助开发者快速读取、创建和编辑 UE 蓝图——无需记忆复杂的节点名称和操作流程，只需用自然语言描述你的需求即可。</p><p>NexusFlow 作为一个独立的桌面应用运行在你的电脑上，通过配套的 UE 插件与虚幻引擎编辑器实时通信。从 0.2.0 开始，桌面主程序还内置 MCP Server，支持 Cursor、Claude Code 等外部 IDE / Agent 接入同一套 UE 自动化能力。</p><p><img src="'+l+'" alt="UE 蓝图编辑器与 NexusFlow 侧边栏并排工作"></p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="🤖-ai-对话" tabindex="-1">🤖 AI 对话 <a class="header-anchor" href="#🤖-ai-对话" aria-label="Permalink to &quot;🤖 AI 对话&quot;">​</a></h3><p>通过自然语言与 AI 交流，描述你想要的蓝图操作：</p><ul><li>读取并解释蓝图逻辑</li><li>创建新的蓝图节点和连线</li><li>修改现有蓝图的结构和属性</li><li>管理蓝图变量、函数和事件</li><li>搜索和使用 UE Skills</li></ul><h3 id="🔮-悬浮球" tabindex="-1">🔮 悬浮球 <a class="header-anchor" href="#🔮-悬浮球" aria-label="Permalink to &quot;🔮 悬浮球&quot;">​</a></h3><p><img src="'+e+`" alt="NexusFlow 悬浮球"></p><p>桌面上的快速入口——一个蓝紫色渐变的圆形图标：</p><ul><li>点击打开 AI 对话侧边栏</li><li>支持拖拽移动，自动吸附到屏幕边缘</li><li>可通过系统托盘控制显示/隐藏</li></ul><h3 id="💬-ai-对话侧边栏" tabindex="-1">💬 AI 对话侧边栏 <a class="header-anchor" href="#💬-ai-对话侧边栏" aria-label="Permalink to &quot;💬 AI 对话侧边栏&quot;">​</a></h3><p>功能丰富的对话界面：</p><ul><li>支持三种窗口模式：浮动窗口、停靠左侧、停靠右侧</li><li>实时显示 UE 连接状态和当前模型</li><li>工具调用状态追踪</li><li>支持停止 AI 生成</li></ul><h3 id="⚡-ue-快速菜单" tabindex="-1">⚡ UE 快速菜单 <a class="header-anchor" href="#⚡-ue-快速菜单" aria-label="Permalink to &quot;⚡ UE 快速菜单&quot;">​</a></h3><p>通过 <strong>4 个入口</strong>、<strong>17 项操作</strong>，在 UE 编辑器内直接调用 AI：</p><ul><li><strong>蓝图编辑器右键</strong> — 13 项操作（解释、优化、提取、修复、文档补全…）</li><li><strong>内容浏览器右键</strong> — 解释或生成整个蓝图资产的文档</li><li><strong>蓝图编辑器工具栏</strong> — 审查和总结当前蓝图</li><li><strong>关卡编辑器工具栏</strong> — NexusFlow 按钮，带连接状态指示</li><li>智能过滤：菜单根据节点选择状态（未选中 / 单选 / 多选）动态显示</li></ul><h3 id="🔌-mcp-server-与外部-ide-接入" tabindex="-1">🔌 MCP Server 与外部 IDE 接入 <a class="header-anchor" href="#🔌-mcp-server-与外部-ide-接入" aria-label="Permalink to &quot;🔌 MCP Server 与外部 IDE 接入&quot;">​</a></h3><p>NexusFlow 0.2.0 可以作为 MCP 服务运行，让支持 MCP 的 IDE / Agent 直接使用 NexusFlow 的 UE 能力：</p><ul><li>检查 NexusFlow 与 UE 插件连接状态</li><li>读取当前 UE 编辑器上下文</li><li>搜索并加载 NexusFlow Skills</li><li>执行蓝图、Widget、资产等受支持操作</li><li>搜索蓝图节点和复用模板</li></ul><p>配套的 <code>nexusflow-skill</code> 为 AGENTS、Claude Code 和 Cursor 提供可移植接入说明，帮助外部 Agent 按安全流程使用 MCP 工具。</p><h3 id="🧪-widget-blueprint-skill-mvp" tabindex="-1">🧪 Widget Blueprint Skill MVP <a class="header-anchor" href="#🧪-widget-blueprint-skill-mvp" aria-label="Permalink to &quot;🧪 Widget Blueprint Skill MVP&quot;">​</a></h3><p>实验性的 Widget Skill 已可试用，可通过自然语言创建和修改 UMG Widget Blueprint，支持 Widget Tree 读写、属性级 patch 和真实预览截图验证。</p><h3 id="⚙️-设置中心" tabindex="-1">⚙️ 设置中心 <a class="header-anchor" href="#⚙️-设置中心" aria-label="Permalink to &quot;⚙️ 设置中心&quot;">​</a></h3><p>iOS 风格的设置界面，管理所有配置：</p><ul><li>AI 模型管理（支持多模型切换）</li><li>Agent 行为参数</li><li>快捷键自定义</li><li>外观主题和语言</li></ul><h3 id="🌐-多语言支持" tabindex="-1">🌐 多语言支持 <a class="header-anchor" href="#🌐-多语言支持" aria-label="Permalink to &quot;🌐 多语言支持&quot;">​</a></h3><ul><li>界面语言：简体中文、繁體中文、English</li><li>AI 回复语言可独立设置</li></ul><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p>NexusFlow 由三个核心组件协同工作：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────┐    IPC 通信    ┌──────────────┐    FFI    ┌──────────────┐</span></span>
<span class="line"><span>│  Tauri 桌面应用 │ ◄──────────► │  Rust Bridge  │ ◄──────► │   UE 插件     │</span></span>
<span class="line"><span>│  (React + Rust) │              │  (通信 + 转换) │          │  (C++ + Py)   │</span></span>
<span class="line"><span>└────────────────┘              └──────────────┘          └──────────────┘</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        │ SSE (Server-Sent Events)</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  ┌──────────────┐</span></span>
<span class="line"><span>  │   LLM API    │</span></span>
<span class="line"><span>  │  (云端模型)   │</span></span>
<span class="line"><span>  └──────────────┘</span></span></code></pre></div><ul><li><strong>Tauri 桌面应用</strong>：提供 AI 对话界面（React 前端）、LLM API 代理（Rust 后端）和内置 MCP Server</li><li><strong>Rust Bridge</strong>：负责桌面应用与 UE 插件之间的 IPC 通信，以及蓝图数据的格式转换</li><li><strong>UE 插件</strong>：在虚幻引擎内执行蓝图操作，提供 Python Skills 系统</li></ul><h3 id="数据流" tabindex="-1">数据流 <a class="header-anchor" href="#数据流" aria-label="Permalink to &quot;数据流&quot;">​</a></h3><p>当你发送一条消息时：</p><ol><li>消息通过 Tauri 应用发送到 LLM（如 GPT-5、Claude 等）</li><li>LLM 分析请求，决定需要调用哪些工具</li><li>工具调用由桌面应用或外部 MCP Client 发起，并通过 Rust Bridge 转发到 UE 插件</li><li>UE 插件执行蓝图操作（读取、修改、创建等）</li><li>结果原路返回，AI 整理后在对话中展示</li></ol><h2 id="支持的-llm-提供商" tabindex="-1">支持的 LLM 提供商 <a class="header-anchor" href="#支持的-llm-提供商" aria-label="Permalink to &quot;支持的 LLM 提供商&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Provider</th><th>说明</th></tr></thead><tbody><tr><td><strong>OpenAI</strong></td><td>GPT 系列，综合能力强</td></tr><tr><td><strong>Anthropic</strong></td><td>Claude 系列，推理能力出色</td></tr><tr><td><strong>Google Gemini</strong></td><td>Gemini 系列，多模态支持</td></tr><tr><td><strong>DeepSeek</strong></td><td>DeepSeek 系列，性价比高</td></tr><tr><td><strong>智谱 GLM</strong></td><td>GLM 系列，Coding 专长</td></tr><tr><td><strong>MiniMax</strong></td><td>MiniMax 系列，Agent 工作流出色</td></tr><tr><td><strong>通义千问</strong></td><td>Qwen 系列，百万上下文</td></tr><tr><td><strong>Kimi</strong></td><td>Kimi 系列，多模态 + Coding</td></tr><tr><td><strong>Custom</strong></td><td>任何兼容以上协议的第三方 API</td></tr></tbody></table><p>你可以同时配置多个模型，并在设置中切换默认使用的模型。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./getting-started">快速入门</a> — 5 分钟完成安装和配置</li><li><a href="./ai-chat">AI 对话</a> — 了解对话界面的详细功能</li><li><a href="./blueprint-operations">蓝图操作</a> — 常用对话示例和详细操作说明</li><li><a href="./mcp">在 IDE / Agent 中使用 NexusFlow</a> — 在 Cursor、Claude Code 等外部 IDE 中使用 NexusFlow</li><li><a href="./widget-skill">Widget Skill</a> — 试用 UMG Widget Blueprint 生成与修改</li></ul>`,42)])])}const P=t(n,[["render",o]]);export{x as __pageData,P as default};
